<?php if (!function_exists('finrep_h')) { function finrep_h($value) { return htmlspecialchars((string)$value, ENT_QUOTES, 'UTF-8'); } } ?>
<script src="<?=base_url();?>assets/plugins/chartjs/Chart.min.js"></script>
<style>.cak-card{border:1px solid #e5e7eb;background:#fff;padding:12px;margin-bottom:12px}.cak-card h4{margin:0 0 4px;font-size:14px;font-weight:700}.cak-value{font-size:20px;font-weight:700}.cak-table th,.cak-table td{font-size:12px;vertical-align:middle!important;white-space:nowrap}.cak-low td{background:#fff7ed!important}.cak-neg td{background:#fee2e2!important}.cak-toolbar{margin-bottom:14px}.cak-chart-wrap{height:320px;position:relative}</style>
<section class="content-header"><h1>Proyeksi Ketersediaan Kas <small>Finance Reports</small></h1><ol class="breadcrumb"><li><a href="<?=base_index();?>"><i class="fa fa-dashboard"></i> Home</a></li><li><a href="<?=base_index();?>finance-report">Finance Reports</a></li><li class="active">Proyeksi Ketersediaan Kas</li></ol></section>
<section class="content"><div class="box box-primary"><div class="box-header with-border"><h3 class="box-title">Cash Availability Projection</h3></div><div class="box-body">
<form id="form_cak" class="form-horizontal cak-toolbar"><div class="form-group"><label class="control-label col-md-1">Start</label><div class="col-md-2"><input type="date" id="start_date" name="start_date" class="form-control" value="<?=date('Y-m-d');?>"></div><label class="control-label col-md-1">Horizon</label><div class="col-md-2"><input type="number" id="horizon_value" name="horizon_value" class="form-control" value="90" min="1" max="365"></div><div class="col-md-2"><select id="horizon_unit" name="horizon_unit" class="form-control"><option value="days">Hari</option><option value="months">Bulan</option></select></div><label class="control-label col-md-1">Min Cash</label><div class="col-md-2"><input type="number" id="minimum_cash" name="minimum_cash" class="form-control" value="0" step="0.01"></div><div class="col-md-1"><button type="submit" id="btn_filter" class="btn btn-primary"><i class="fa fa-search"></i></button></div></div></form>
<p class="text-muted"><i class="fa fa-info-circle"></i> Read-only. Kas awal dari saldo akun kas/bank; proyeksi dari dokumen AR/AP open dan payment planning yang tersedia.</p><div id="cak_alert" class="alert alert-danger" style="display:none"></div>
<div class="row"><div class="col-md-3"><div class="cak-card"><h4>Opening Cash</h4><div id="cak_opening" class="cak-value">0.00</div></div></div><div class="col-md-3"><div class="cak-card"><h4>Total Inflow</h4><div id="cak_inflow" class="cak-value text-green">0.00</div></div></div><div class="col-md-3"><div class="cak-card"><h4>Total Outflow</h4><div id="cak_outflow" class="cak-value text-red">0.00</div></div></div><div class="col-md-3"><div class="cak-card"><h4>Minimum Ending</h4><div id="cak_min" class="cak-value">0.00</div></div></div></div>
<div id="cak_warning"></div><div class="cak-chart-wrap"><canvas id="cak_chart"></canvas></div><div id="cak_result" style="margin-top:14px"><div class="text-center text-muted" style="padding:30px">Klik filter untuk memuat proyeksi.</div></div></div></div></section>
<script>
$(function(){var cakChart=null;function num(v){v=parseFloat(v||0);return v.toLocaleString('en-US',{minimumFractionDigits:2,maximumFractionDigits:2});}function renderChart(chart){var ctx=document.getElementById('cak_chart').getContext('2d');if(cakChart&&cakChart.destroy)cakChart.destroy();cakChart=new Chart(ctx).Line({labels:chart.labels,datasets:[{label:'Ending Cash',fillColor:'rgba(15,118,110,0.12)',strokeColor:'#0f766e',pointColor:'#0f766e',pointStrokeColor:'#fff',data:chart.ending},{label:'Inflow',fillColor:'rgba(34,197,94,0.12)',strokeColor:'#16a34a',pointColor:'#16a34a',pointStrokeColor:'#fff',data:chart.inflow},{label:'Outflow',fillColor:'rgba(239,68,68,0.10)',strokeColor:'#dc2626',pointColor:'#dc2626',pointStrokeColor:'#fff',data:chart.outflow}]},{responsive:true,maintainAspectRatio:false,bezierCurve:false,datasetFill:false});}
function loadReport(){$('#cak_alert').hide().text('');$('#cak_result').html('<div class="text-center" style="padding:30px"><i class="fa fa-spinner fa-spin fa-2x"></i><br>Loading...</div>');$('#btn_filter').prop('disabled',true);$.ajax({url:'<?=base_admin();?>modul/finance_report/finance_report_proyeksi_ketersediaan_kas_action.php?act=filter',type:'POST',dataType:'json',data:$('#form_cak').serialize()}).done(function(res){if(res.status==='success'){$('#cak_result').html(res.html);$('#cak_opening').text(num(res.summary.opening_cash));$('#cak_inflow').text(num(res.summary.total_inflow));$('#cak_outflow').text(num(res.summary.total_outflow));$('#cak_min').text(num(res.summary.minimum_ending));$('#cak_min').toggleClass('text-red',parseFloat(res.summary.minimum_ending)<parseFloat($('#minimum_cash').val()||0));$('#cak_warning').html(res.warning_html||'');renderChart(res.chart);}else{$('#cak_result').html('<div class="alert alert-danger">'+(res.message||'Proyeksi gagal diproses.')+'</div>');$('#cak_alert').text(res.message||'Proyeksi gagal diproses.').show();}}).fail(function(xhr){$('#cak_result').html('<div class="alert alert-danger">Server error</div>');$('#cak_alert').text(xhr.responseText||'Server error').show();}).always(function(){$('#btn_filter').prop('disabled',false);});}
$('#form_cak').on('submit',function(e){e.preventDefault();loadReport();});$('#horizon_unit').on('change',function(){if(this.value==='months'){$('#horizon_value').attr('max',24).val(Math.min(parseInt($('#horizon_value').val()||3,10),12)||3);}else{$('#horizon_value').attr('max',365).val(90);}});loadReport();});
</script>
